ontesto($contesto);				$model = ImmaginitipologieModel::getModel($contesto);				if ($model && $model->clear()->whereId((int)$id)->rowNumber())		{			$pkName = $model->getPrimaryKey();						$data['records'] = $this->m['ImmaginiarchiviModel']->clear()->where(array(				$pkName	=>	(int)$id,			))->orderBy('id_order')->send();						$data['contesto'] = sanitizeHtml($contesto);						$this->append($data);			$this->load('view');		}	}		public function upload()	{		header('Content-type: application/json');				$this->shift();				$this->clean();				$result = "KO";		$immagine = "";		$errore = "";				$this->checkCsrf(true, "POST");				$contesto = $this->request->post("contesto","",'sanitizeAll');		$id = $this->request->post("id",0,'forceInt');				$this->checkContesto($contesto);				$model = ImmaginitipologieModel::getModel($contesto);				if (!$model || !$model->clear()->whereId((int)$id)->rowNumber())		{			echo json_encode(array(				"result"	=>	$result,				"immagine"	=>	$immagine,				"immagine_clean"	=>	$immagine,				"error"		=>	gtext("Contesto non ammesso"),			));						die();		}				$pkName = $model->getPrimaryKey();				$this->m("ImmaginiarchiviModel")->setValues(array(			"contesto"	=>	$contesto,			"immagine"	=>	"",			"$pkName"	=>	(int)$id,		));				$erroreGenerico = gtext("Errore caricamento file: ");		$testoSuccesso = "";				if (isset($_FILES["immagine"]["name"]))			$erroreGenerico .= "<b>".sanitizeHtml($_FILES["immagine"]["name"])."</b> ";			$testoSuccesso = gtext("File")." ".sanitizeHtml($_FILES["immagine"]["name"])." ".gtext("correttamente caricato");				if ($this->m("ImmaginiarchiviModel")->upload("insert"))		{			$immagine = sanitizeHtml(basename($this->m("ImmaginiarchiviModel")->values["immagine"]));						$this->m("ImmaginiarchiviModel")->setValue("estensione", $this->m("ImmaginiarchiviModel")->files->ext);			$this->m("ImmaginiarchiviModel")->setValue("content_type", $this->m("ImmaginiarchiviModel")->files->mimeType);						if ($this->m("ImmaginiarchiviModel")->insert())			{				$errore = $testoSuccesso;								$result = "OK";			}			else				$errore = $erroreGenerico.strip_tags($this->m("ImmaginiarchiviModel")->notice);		}		else			$errore = $erroreGenerico.strip_tags($this->m("ImmaginiarchiviModel")->notice);				echo json_encode(array(			"result"	=>	$result,			"immagine"	=>	$immagine,			"immagine_clean"	=>	$immagine,			"error"		=>	$errore,		));	}		public function ordina()	{		$clean["order"] = $this->request->post("order","","sanitizeAll");				$orderArray = explode(",",$clean["order"]);				foreach ($orderArray as $id)		{			if ((int)$id !== 0)				$this->checkContesto($this->m("ImmaginiarchiviModel")->clear()->whereId((int)$id)->field("contesto"));		}				$this->modelName = "ImmaginiarchiviModel";				parent::ordina();	}	public function erase($id_immagine = null)	{		$this->checkCsrf(true);				$this->checkContesto($this->m("ImmaginiarchiviModel")->clear()->whereId((int)$id_immagine)->field("contesto"));				$this->clean();		if (isset($id_immagine))		{			$clean['id_immagine'] = (int)$id_immagine;			$this->m['ImmaginiarchiviModel']->del($clean['id_immagine']);		}	}		public function rotateo($id_immagine = null)	{		$this->checkCsrf(true);				$this->checkContesto($this->m("ImmaginiarchiviModel")->clear()->whereId((int)$id_immagine)->field("contesto"));				$this->clean();				if (isset($id_immagine))		{			$clean['id_immagine'] = (int)$id_immagine;			$immagine = $this->m['ImmaginiarchiviModel']->selectId($clean['id_immagine']);						if (!empty($immagine))			{				$path = Domain::$parentRoot."/".Parametri::$cartellaImmaginiArchivi;								if (is_file($path."/".$immagine["immagine"]))				{					$thumb = new Image_Gd_Thumbnail($path);										$thumb->imageRotations[] = array(						"angle"	=>	270,					);										$thumb->render($immagine["immagine"], $path."/".$immagine["immagine"]);				}			}		}	}}